import{_ as a,c as e,o as s,a1 as r}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"進階配置：高級功能詳解 | Antigravity-Manager","description":"學習 Antigravity-Manager 的進階配置方法。掌握帳號調度、模型路由、配額治理和監控統計等高級功能。","frontmatter":{"title":"進階配置：高級功能詳解 | Antigravity-Manager","order":300,"sidebarTitle":"將系統升級到生產級","subtitle":"進階配置：高級功能詳解","description":"學習 Antigravity-Manager 的進階配置方法。掌握帳號調度、模型路由、配額治理和監控統計等高級功能。"},"headers":[],"relativePath":"zh-tw/lbjlaq/Antigravity-Manager/advanced/index.md","filePath":"zh-tw/lbjlaq/Antigravity-Manager/advanced/index.md"}'),n={name:"zh-tw/lbjlaq/Antigravity-Manager/advanced/index.md"};function d(o,t,i,l,p,c){return s(),e("div",null,[...t[0]||(t[0]=[r(`<h1 id="進階配置" tabindex="-1">進階配置 <a class="header-anchor" href="#進階配置" aria-label="Permalink to &quot;進階配置&quot;">​</a></h1><p>本章節深入講解 Antigravity Tools 的高級功能：配置管理、安全策略、帳號調度、模型路由、配額治理、監控統計，以及伺服器部署方案。掌握這些內容後，你可以把 Antigravity Tools 從&quot;能用&quot;升級到&quot;好用、穩定、可運維&quot;。</p><h2 id="本章包含" tabindex="-1">本章包含 <a class="header-anchor" href="#本章包含" aria-label="Permalink to &quot;本章包含&quot;">​</a></h2><table tabindex="0"><thead><tr><th>教程</th><th>說明</th></tr></thead><tbody><tr><td><a href="./config/">配置全解</a></td><td>AppConfig/ProxyConfig 的完整欄位、落盤位置與熱更新語義</td></tr><tr><td><a href="./security/">安全與隱私</a></td><td><code>auth_mode</code>、<code>allow_lan_access</code> 與安全基線設計</td></tr><tr><td><a href="./scheduling/">高可用調度</a></td><td>輪換、固定帳號、黏性會話與失敗重試機制</td></tr><tr><td><a href="./model-router/">模型路由</a></td><td>自訂映射、萬用字元優先順序與預設策略</td></tr><tr><td><a href="./quota/">配額治理</a></td><td>Quota Protection + Smart Warmup 的組合打法</td></tr><tr><td><a href="./monitoring/">Proxy Monitor</a></td><td>請求日誌、篩選、詳情還原與匯出</td></tr><tr><td><a href="./token-stats/">Token Stats</a></td><td>成本視角的統計口徑與圖表解讀</td></tr><tr><td><a href="./context-compression/">長會話穩定性</a></td><td>上下文壓縮、簽名快取與工具結果壓縮</td></tr><tr><td><a href="./system/">系統能力</a></td><td>多語言/主題/更新/開機自啟/HTTP API Server</td></tr><tr><td><a href="./deployment/">伺服器部署</a></td><td>Docker noVNC vs Headless Xvfb 選型與運維</td></tr></tbody></table><h2 id="學習路徑建議" tabindex="-1">學習路徑建議 <a class="header-anchor" href="#學習路徑建議" aria-label="Permalink to &quot;學習路徑建議&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">推薦順序</p><p>本章內容較多，建議按以下模組分批學習：</p></div><p><strong>第一階段：配置與安全（必學）</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>配置全解 → 安全與隱私</span></span>
<span class="line"><span>config      security</span></span></code></pre></div><p>先了解配置體系（哪些需要重啟、哪些熱更新），再學安全設定（尤其是暴露到區域網路/公網時）。</p><p><strong>第二階段：調度與路由（推薦）</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>高可用調度 → 模型路由</span></span>
<span class="line"><span>scheduling    model-router</span></span></code></pre></div><p>學會用最小帳號數獲得最大穩定性，再用模型路由遮蔽上游變化。</p><p><strong>第三階段：配額與監控（按需）</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>配額治理 → Proxy Monitor → Token Stats</span></span>
<span class="line"><span>quota        monitoring      token-stats</span></span></code></pre></div><p>防止配額無感耗盡，把呼叫黑盒變成可觀測系統，量化成本優化。</p><p><strong>第四階段：穩定性與部署（進階）</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>長會話穩定性 → 系統能力 → 伺服器部署</span></span>
<span class="line"><span>context-compression  system    deployment</span></span></code></pre></div><p>解決長會話的隱性問題，讓客戶端更像產品，最後學伺服器部署。</p><p><strong>快速選擇</strong>：</p><table tabindex="0"><thead><tr><th>你的場景</th><th>推薦先看</th></tr></thead><tbody><tr><td>多帳號輪換不穩定</td><td><a href="./scheduling/">高可用調度</a></td></tr><tr><td>想固定某個模型名</td><td><a href="./model-router/">模型路由</a></td></tr><tr><td>配額總是用完</td><td><a href="./quota/">配額治理</a></td></tr><tr><td>想看請求日誌</td><td><a href="./monitoring/">Proxy Monitor</a></td></tr><tr><td>想統計 Token 消耗</td><td><a href="./token-stats/">Token Stats</a></td></tr><tr><td>長對話經常出錯</td><td><a href="./context-compression/">長會話穩定性</a></td></tr><tr><td>要暴露到區域網路</td><td><a href="./security/">安全與隱私</a></td></tr><tr><td>要部署到伺服器</td><td><a href="./deployment/">伺服器部署</a></td></tr></tbody></table><h2 id="前置條件" tabindex="-1">前置條件 <a class="header-anchor" href="#前置條件" aria-label="Permalink to &quot;前置條件&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">開始前請確認</p><ul><li>已完成 <a href="./../start/">快速開始</a> 章節（至少完成安裝、新增帳號、啟動反代）</li><li>已完成 <a href="./../platforms/">平台與整合</a> 中至少一個協議的接入（如 OpenAI 或 Anthropic）</li><li>本地反代已能正常回應請求</li></ul></div><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><p>學完本章節後，你可以繼續學習：</p><ul><li><a href="./../faq/">常見問題</a>：遇到 401/404/429/流式中斷等問題時的排查指南</li><li><a href="./../appendix/">附錄</a>：端點速查表、資料模型、z.ai 能力邊界等參考資料</li></ul>`,25)])])}const g=a(n,[["render",d]]);export{u as __pageData,g as default};
